const rows = $input.all().map(i => i.json);
const data = rows.map(r => ({
  company: r.company||'', title: r.title||'', url: r.url||'', loc: r.locations||'',
  career: (r.min_career!=null?r.min_career:'') + (r.max_career!=null?('~'+r.max_career):(r.min_career!=null?'+':'')),
  status: r.status||'', source: r.source||'',
  tech: Array.isArray(r.tech_stacks)?r.tech_stacks.join(', '):(r.tech_stacks||''),
  summary: (r.summary||'').slice(0,300),
  collected: String(r.collected_at||'').slice(0,10)
}));
const html = '<!doctype html><html lang="ko"><head><meta charset="utf-8"><meta name="viewport" content="width=device-width,initial-scale=1"><title>n8n DB 뷰어</title><style>' + "
*{box-sizing:border-box}body{font-family:-apple-system,Segoe UI,Roboto,sans-serif;margin:0;padding:16px;background:#f7f8fa;color:#1a1a1a}
h1{font-size:18px;margin:0 0 12px}.filters{display:flex;gap:8px;flex-wrap:wrap;align-items:center;margin-bottom:12px}
select,input,button{padding:6px 8px;border:1px solid #ccc;border-radius:6px;font-size:13px}input{min-width:180px}
button{background:#2d6cdf;color:#fff;border:none;cursor:pointer}
table{width:100%;border-collapse:collapse;background:#fff;font-size:13px}
th,td{padding:6px 8px;border-bottom:1px solid #eee;text-align:left;vertical-align:top}
th{position:sticky;top:0;background:#f0f2f5;z-index:1}
td.tech{color:#555;max-width:220px}a{color:#2d6cdf;text-decoration:none}a:hover{text-decoration:underline}
.b{padding:2px 6px;border-radius:10px;font-size:11px}.b-done{background:#e3f5e9;color:#1a7f43}.b-pending{background:#fff3d6;color:#8a6d00}.b-failed{background:#fde3e3;color:#b3261e}
" + '</style></head><body>'
  + '<h1>공고 DB (<span id="cnt"></span>건)</h1>'
  + '<div class="filters">상태 <select id="fStatus"></select> 소스 <select id="fSource"></select> 지역 <select id="fLoc"></select> <input id="fText" placeholder="회사/제목 빠른 필터"> <button onclick="location.reload()">새로고침</button></div>'
  + '<table><thead><tr><th>회사</th><th>제목</th><th>지역</th><th>경력</th><th>상태</th><th>소스</th><th>기술스택</th><th>수집</th></tr></thead><tbody id="tb"></tbody></table>'
  + '<script>const DATA=' + JSON.stringify(data) + ';' + "
function esc(s){return String(s==null?'':s).replace(/[&<>"]/g,function(c){return{'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;'}[c];});}
function opt(id,vals,cb){var e=document.getElementById(id);e.innerHTML='<option value="">전체</option>'+vals.map(function(v){return '<option>'+esc(v)+'</option>';}).join('');e.onchange=cb;}
function render(){
  var s=v('fStatus'),sr=v('fSource'),lc=v('fLoc'),t=v('fText').toLowerCase();
  var rows=DATA.filter(function(d){return (!s||d.status===s)&&(!sr||d.source===sr)&&(!lc||(d.loc||'').indexOf(lc)>=0)&&(!t||((d.company||'')+(d.title||'')).toLowerCase().indexOf(t)>=0);});
  document.getElementById('cnt').textContent=rows.length;
  var h=rows.map(function(d){return '<tr><td>'+esc(d.company)+'</td><td><a href="'+esc(d.url)+'" target="_blank" title="'+esc(d.summary)+'">'+esc(d.title)+'</a></td><td>'+esc(d.loc)+'</td><td>'+esc(d.career)+'</td><td><span class="b b-'+esc(d.status)+'">'+esc(d.status)+'</span></td><td>'+esc(d.source)+'</td><td class="tech">'+esc(d.tech)+'</td><td>'+esc(d.collected)+'</td></tr>';}).join('');
  document.getElementById('tb').innerHTML=h;
}
function v(id){return document.getElementById(id).value;}
function uniq(k){return Array.from(new Set(DATA.map(function(d){return d[k];}).filter(Boolean))).sort();}
opt('fStatus',uniq('status'),render);opt('fSource',uniq('source'),render);opt('fLoc',uniq('loc'),render);
document.getElementById('fText').oninput=render;render();
" + '</script>'
  + '</body></html>';
return { json: { html } };
